        if valid &lt; self.min_valid:
            msg = f"valid fraction {valid:.1%} below {self.min_valid:.0%}"
            if self.on_fail == "raise":
                raise QCError(msg)
            print(f"  WARNING: {msg}")
        return x

    def get_config(self) -&gt; dict:
        return {"min_valid": self.min_valid, "on_fail": self.on_fail}


