        k = self._key(x)
        if k in self._store:
            self._hits += 1
            return self._store[k]
        self._misses += 1
        out = self.inner(x)
        self._store[k] = out
        return out

    def get_config(self) -&gt; dict:
        return {"inner": type(self.inner).__name__}


